// ===== PARTICLES =====
(function(){
  const canvas = document.getElementById('particles-canvas');
  const ctx = canvas.getContext('2d');
  let W, H, particles = [];

  function resize(){
    W = canvas.width = window.innerWidth;
    H = canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  function rand(a,b){ return Math.random()*(b-a)+a; }

  for(let i=0;i<60;i++){
    particles.push({
      x: rand(0,1), y: rand(0,1),
      size: rand(0.5,2.5),
      speed: rand(0.0002,0.0006),
      opacity: rand(0.1,0.5),
      phase: rand(0,Math.PI*2)
    });
  }

  function draw(){
    ctx.clearRect(0,0,W,H);
    const t = Date.now()*0.001;
    particles.forEach(p=>{
      p.y -= p.speed;
      if(p.y<0){ p.y=1; p.x=rand(0,1); }
      const op = p.opacity * (0.5 + 0.5*Math.sin(t*0.5 + p.phase));
      ctx.beginPath();
      ctx.arc(p.x*W, p.y*H, p.size, 0, Math.PI*2);
      ctx.fillStyle = `rgba(212,175,55,${op})`;
      ctx.fill();
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

// ===== QR CODE =====
let currentQR = null;
function showQR(btn, url){
  document.querySelectorAll('.qr-tab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  const display = document.getElementById('qr-display');
  display.innerHTML = '';
  currentQR = new QRCode(display, {
    text: url,
    width: 160,
    height: 160,
    colorDark: '#000000',
    colorLight: '#ffffff',
    correctLevel: QRCode.CorrectLevel.H
  });
}

window.addEventListener('load', function(){
  showQR(document.querySelector('.qr-tab.active'), 'https://www.instagram.com/m0ody.1.0');
});